LAYER
	#DEBUG 2
  	NAME "routes_ign"
  	TYPE LINE
  	STATUS ON
  	CONNECTIONTYPE OGR
  	CONNECTION "roadnetwork_forestimator_20260325.gpkg"
  	DATA "roadnetwork_forestimator_20260325"
  	PROJECTION
            "init=epsg:3812"
        END
  	#LABELITEM    "categorie"    
  	CLASSITEM "categorie"
  	CLASS
    		NAME "C0-C1" # jaune
    		EXPRESSION {C0,C1}
    		STYLE
      			#COLOR 88 90 8
      			OUTLINECOLOR 95 97 8
      			WIDTH 6
    		END #style
  	END #class
  	CLASS
    		NAME "C2-C3" 
    		EXPRESSION {C2,C3}
    		STYLE
      			COLOR 40 40 40
      			OUTLINECOLOR 200 200 200
      			WIDTH 4
    		END #style
  	END #class
  	CLASS
    		NAME "X,dirt and path "
    		EXPRESSION {X,DIRT,PATH}
    		STYLE
      			COLOR 100 100 100
      			OUTLINECOLOR 200 200 200
      			WIDTH 4
      			INITIALGAP 2
  			PATTERN 36 14 END
    		END #style
  	END #class
	END #layer
	
	LAYER
  	NAME "routes"
  	TYPE LINE
  	STATUS ON
  	CONNECTIONTYPE OGR
  	CONNECTION "pistes_dnf.gpkg"
  	DATA "pistes_dnf"
  	PROJECTION
            "init=epsg:31370"
        END 
  	CLASSITEM "categorie"
  	CLASS
    		NAME "1C" 
    		EXPRESSION {1C}
    		  STYLE
    			SYMBOL "linie-gestr4"
    			SIZE 2
    			COLOR 0 0 0
  		END
  	END #class
  	CLASS
    		NAME "2C" 
    		EXPRESSION {2C}
    		STYLE
      			OUTLINECOLOR 255 0 0
      			WIDTH 2
    		END #style
  	END #class
  	CLASS
    		NAME "3C"
    		EXPRESSION {3C}
    		STYLE
      			OUTLINECOLOR 255 0 0
      			WIDTH 2
      			INITIALGAP 2
  			PATTERN 36 14 END
    		END #style
  	END #class
	END #layer
